body.script:
// 
(function(){
  var c=document.getElementById('bgCanvas'),ctx=c.getContext('2d');
  function res(){c.width=window.innerWidth;c.height=window.innerHeight}
  res();window.addEventListener('resize',res);
  var pts=[];
  for(var i=0;i<50;i++)pts.push({x:Math.random()*c.width,y:Math.random()*c.height,vx:(Math.random()-.5)*.5,vy:(Math.random()-.5)*.5});
  function draw(){
    ctx.clearRect(0,0,c.width,c.height);
    ctx.fillStyle='rgba(0,0,255,0.3)';
    pts.forEach(p=>{
      ctx.beginPath();ctx.arc(p.x,p.y,2,0,Math.PI*2);ctx.fill();
      p.x+=p.vx;p.y+=p.vy;
      if(p.x<0||p.x>c.width)p.vx*=-1;if(p.y<0||p.y>c.height)p.vy*=-1;
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

const FOLDERS=[
  {id:'games',name:'Games',color:'#3b82f6',projects:[
    {name:'SN GN Math 2026',desc:'USE ME TO PLAY GAMES!',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/Story-Network-GN-Math-2026@latest/index.html'},
    {name:'SN Smash Bros',desc:'Fighting Game',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/SN-Smash-Bros@latest/index.html'}
  ]},
  {id:'proxy',name:'Proxy',color:'#22c55e',projects:[
    {name:'Zicon',desc:'Browser Engine',url:'https://cdn.jsdelivr.net/gh/storynetwork-camzzz/Zicon@latest/index.html'}
  ]}
];

const homeGrid=document.getElementById('folder-grid');
FOLDERS.forEach(f=>{
  const div=document.createElement('div');
  div.className='folder-card';
  div.innerHTML=`<div class="folder-card-name" style="color:${f.color}">${f.name}</div><div style="font-size:0.7rem; color:#4a4a88">${f.projects.length} Projects</div><button class="folder-card-btn" style="background:${f.color}">OPEN FOLDER</button>`;
  div.onclick=()=>openFolder(f);
  homeGrid.appendChild(div);
});

function openFolder(f){
  document.getElementById('view-home').style.display='none';
  document.getElementById('view-folder').style.display='block';
  document.getElementById('back-btn').className='visible';
  document.getElementById('fv-title').textContent=f.name;
  const pg=document.getElementById('project-grid');
  pg.innerHTML='';
  f.projects.forEach(p=>{
    const div=document.createElement('div');
    div.className='card';
    div.innerHTML=`<div class="card-name">${p.name}</div><p style="font-size:0.75rem; color:#4a4a88">${p.desc}</p><button class="card-btn">LAUNCH</button>`;
    div.onclick=()=>openModal(p);
    pg.appendChild(div);
  });
}

function goHome(){
  document.getElementById('view-home').style.display='block';
  document.getElementById('view-folder').style.display='none';
  document.getElementById('back-btn').className='';
}

let active=null;
function openModal(p){active=p;document.getElementById('modal-name').textContent=p.name;document.getElementById('modal-desc').textContent=p.desc;document.getElementById('overlay').className='open'}
function closeModal(){document.getElementById('overlay').className=''}

function doLaunch(){
  if(!active)return;
  const loader=document.getElementById('loadscreen');
  loader.className='on';
  const frame=document.getElementById('appframe');
  frame.src=active.url;
  frame.style.display='block';
  frame.onload=()=>loader.className='';
  closeModal();
}
//
